import os
from pinecone import Pinecone, ServerlessSpec
from langchain_pinecone import PineconeVectorStore
from langchain_huggingface import HuggingFaceEmbeddings
from langchain.tools import tool
from langchain.agents import create_agent
from langchain_groq import ChatGroq

# ---------- 1. Embeddings + Pinecone setup ----------
embeddings = HuggingFaceEmbeddings(model_name="sentence-transformers/all-MiniLM-L6-v2")

os.environ["PINECONE_API_KEY"] = "pcsk_6wW9qC_LooJkWkKU78wD8npikdWA1XSD6nHXKcdssbQzwzVJkJqxfiAzB2RJNN5zXRShTg"
pc = Pinecone(api_key=os.environ.get("PINECONE_API_KEY"))
index_name = "book-rag"

index = pc.Index(index_name)

vector_store = PineconeVectorStore(index=index, embedding=embeddings)

# ---------- 2. Retriever ----------
retriever = vector_store.as_retriever(
    search_type="similarity",
    search_kwargs={"k": 4}   # top-4 chunks
)

@tool
def retrieve_context(query: str) -> str:
    """Search the book knowledge base and return relevant context to answer the user's question."""
    docs = retriever.invoke(query)
    if not docs:
        return "No relevant context found."
    return "\n\n".join(f"[Source {i+1}]: {d.page_content}" for i, d in enumerate(docs))

from langchain_groq import ChatGroq
os.environ["GROQ_API_KEY"] = "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"

llm = ChatGroq(
    model="llama-3.3-70b-versatile",
    temperature=0,
)

agent = create_agent(
    model=llm,
    tools=[retrieve_context],
    system_prompt=(
        "You are a helpful assistant. Always use the retrieve_context tool "
        "to fetch relevant information before answering questions about the book. "
        "If the tool returns no useful context, say you don't know."
    ),
)

response = agent.invoke({
    "messages": [{"role": "user", "content": "What is Persistent Storage in Kubernetes?"}]
})

print(response["messages"][-1].content)

response = agent.invoke({
    "messages": [{"role": "user", "content": "WHat are The Benefits of Creating Cloud Native Applications?"}]
})

print(response["messages"][-1].content)